1	import React, {useState, useRef, useMemo, useEffect} from 'react';
2	import ReactDOM from 'react-dom';
3	import {QueryClientProvider} from 'react-query';
4	import {PigmentThemeProvider, Box} from '@customink/pigment-react';
5	import {Provider as RollbarProvider, ErrorBoundary} from '@rollbar/react';
6	import PageErrorFallback from 'components/PageErrorFallback';
7	import {styled} from '@customink/pigment-react/lib/themeCustomink';
8	import useBreakpoint from 'hooks/useBreakpoint';
9	import queryClient from 'src/shared/queryClient';
10	import ProductHero from 'product_details_page/ProductHero';
11	import MoreInfo from 'product_details_page/MoreInfo';
12	import RelatedProducts from 'product_details_page/RelatedProducts';
13	import ProductReviews from 'product_details_page/ProductReviews';
14	import CurrentSelectedColorContext from 'product_details_page/Context/colorContext';
15	import ProductContext from 'product_details_page/Context/productContext';
16	import {
17	  getOctoIdFromCookie,
18	  getSessionFromCookie
19	} from 'algolia_listing_pages/utils/data_utils';
20	import ProductDetailsAndKeyBenefits from 'product_details_page/ProductDetailsSection/ProductDetailsAndKeyBenefits';
21	import CustomerLooks from 'product_details_page/ProductHero/CustomerLooks';
22	import rollbar from 'src/vendor/rollbar';
23	import {RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE} from 'constants/pdpRelatedProducts';
24	import ExtraRecommendations from 'product_details_page/RelatedProducts/ExtraRecommendations';
25	import algoliaImageResolver from 'features/products/components/ProductCard/utils/algoliaImageResolver';
26	import {IMAGE_CONTEXT_PDP} from 'constants/imageContexts';
27	import {searchParams} from 'src/utils/url';
28	import {semantics} from '@customink/design-tokens';
29	import FavoritesProvider, {
30	  PageType
31	} from 'features/favorites/FavoritesProvider';
32	import {ProfilesAuthProvider} from 'features/auth/ProfilesAuthContext';
33	import {
34	  fireUnbundledPriceTestAnalytics,
35	  isBlankPriceHiddenFromPLP,
36	  isPlaPage
37	} from '../utils/abTests/unbundledPriceTest';
38	import MaybeSignalmizelyProvider from 'components/MaybeSignalmizelyProvider';
39	import {AA_TEST_TARGET_STYLE_ID} from '../utils/abTests/signalmizelyAATestAnalytics';
40	
41	const ProductHeroWrapper = styled(Box)({
42	  backgroundColor: semantics.light.neutral.background.primary,
43	  color: semantics.light.neutral.text.primary,
44	  fontSize: '16px',
45	  maxWidth: '100vw',
46	  position: 'relative',
47	  borderTop: `1px solid ${semantics.light.neutral.border.default}`,
48	  marginBottom: 0,
49	  '@media (min-width: 700px)': {
50	    maxWidth: 'none',
51	    borderBottom: `1px solid ${semantics.light.neutral.border.default}`,
52	    marginBottom: '2rem'
53	  }
54	});
55	
56	const ProductDetailsPage = (props) => {
57	  const [currentSelectedColor, setCurrentSelectedColor] = useState(
58	    props.productProps.selectedColor
59	  );
60	  const [reviewsAccordionState, setReviewsAccordionState] = useState(false);
61	  const [similarAccordionState, setSimilarAccordionState] = useState(true);
62	  const [singles, setSingles] = useState(props.productProps.preferSingles);
63	  const reviewRef = useRef(null);
64	  const similarRef = useRef(null);
65	  const {name, productInfo, status, imageConfig, colors, id} =
66	    props.productProps || {};
67	  const sessionToken = getOctoIdFromCookie() || getSessionFromCookie();
68	  window.dataLayer.push({algoliaUserToken: sessionToken});
69	
70	  const breakpoint = useBreakpoint();
71	  const isPreview = useMemo(() => status === 'preview', [status]);
72	  const pdpMobileBreakpoint = breakpoint === 'sm';
73	  const extraRecommendationsAnchor = document.getElementById(
74	    'extra-recommendations'
75	  );
76	
77	  // Store the initial color ID to detect when user changes color
78	  const initialColorId = useRef(props.productProps.selectedColor?.id);
79	  const hasColorChanged = useRef(false);
80	
81	  // Track if user has changed color from initial
82	  // NOTE: hasColorChanged is intentionally never reset to false. Once a user interacts
83	  // with color selection, we permanently switch from using SSR-generated images to
84	  // client-side calculated images for consistency. This prevents flickering if user
85	  // cycles back to the original color.
86	  useEffect(() => {
87	    if (currentSelectedColor?.id !== initialColorId.current) {
88	      hasColorChanged.current = true;
89	    }
90	  }, [currentSelectedColor?.id]);
91	
92	  const hidePriceFromPLP = isBlankPriceHiddenFromPLP();
93	
94	  const hasFiredUnbundledPriceAnalytics = useRef(false);
95	  useEffect(() => {
96	    if (
97	      !hasFiredUnbundledPriceAnalytics.current &&
98	      Boolean(props.productProps.blankPrice) &&
99	      !hidePriceFromPLP &&
100	      !isPlaPage()
101	    ) {
102	      fireUnbundledPriceTestAnalytics({pageType: 'pdp'});
103	      hasFiredUnbundledPriceAnalytics.current = true;
104	    }
105	  }, [props.productProps.blankPrice, hidePriceFromPLP]);
106	
107	  const isAATestTarget = Number(id) === AA_TEST_TARGET_STYLE_ID;
108	
109	  // Derive algolia image - use SSR image only on first render
110	  const algoliaImage = useMemo(() => {
111	    // If no imageConfig, use the SSR image
112	    if (!imageConfig) return props.algoliaImage;
113	
114	    // Only use SSR image if color hasn't changed yet and we have SSR image
115	    // This ensures SSR-generated image is used on initial load for performance
116	    if (
117	      !hasColorChanged.current &&
118	      currentSelectedColor?.id === initialColorId.current &&
119	      props.algoliaImage
120	    ) {
121	      return props.algoliaImage;
122	    }
123	
124	    // User changed color or interacting with page - recalculate
125	    // Pass the laydown image as fallback in case lab image is not available
126	    const styleCardImageUrl = props.mainImage?.[currentSelectedColor?.id]?.src;
127	    // Get cid from URL params for iframe context design handling
128	    const cidFromUrl = searchParams().get('cid');
129	    return algoliaImageResolver({
130	      colorIdOverride: currentSelectedColor?.id,
131	      colors: colors,
132	      imageConfig: imageConfig,
133	      productId: id,
134	      styleCardImageUrl: styleCardImageUrl,
135	      context: IMAGE_CONTEXT_PDP,
136	      iframer: props.iframed,
137	      cid: cidFromUrl
138	    });
139	  }, [
140	    currentSelectedColor?.id,
141	    imageConfig,
142	    colors,
143	    id,
144	    props.algoliaImage,
145	    props.mainImage,
146	    props.iframed
147	  ]);
148	
149	  return (
150	    <RollbarProvider instance={rollbar}>
151	      <ErrorBoundary fallbackUI={PageErrorFallback}>
152	        <MaybeSignalmizelyProvider isEnabled={isAATestTarget} location="pdp">
153	          <QueryClientProvider client={queryClient}>
154	            <PigmentThemeProvider>
155	              <ProfilesAuthProvider>
156	                <FavoritesProvider pageType={PageType.PDP}>
157	                  <ProductContext.Provider
158	                    value={{
159	                      ...props.productProps,
160	                      mainImage: props.mainImage,
161	                      categoryInfo: props.categoryInfo
162	                    }}>
163	                    <CurrentSelectedColorContext.Provider
164	                      value={{
165	                        currentSelectedColor,
166	                        setCurrentSelectedColor,
167	                        reviewsAccordionState,
168	                        setReviewsAccordionState,
169	                        similarAccordionState,
170	                        setSimilarAccordionState,
171	                        singles,
172	                        setSingles,
173	                        algoliaImage
174	                      }}>
175	                      <ProductHeroWrapper>
176	                        <ProductHero
177	                          {...props.productProps}
178	                          mainImage={props.mainImage}
179	                          ttarpNumber={props.ttarpNumber}
180	                          iframed={props.iframed}
181	                          reviewRef={reviewRef}
182	                          similarRef={similarRef}
183	                          samplePrice={props.samplePrice}
184	                          sampleRegularStartingUnitPrice={
185	                            props.sampleRegularStartingUnitPrice
186	                          }
187	                          sampleOrderType={props.sampleOrderType}
188	                          checkoutAction={props.checkoutAction}
189	                          sampleQuoteCid={props.sampleQuoteCid}
190	                          renderSampleForm={props.renderSampleForm}
191	                          blanksOrdering={props.blanksOrdering}
192	                          productProps={props.productProps}
193	                          currentUserInternal={props.currentUserInternal}
194	                        />
195	                      </ProductHeroWrapper>
196	                      <Box
197	                        sx={{
198	                          backgroundColor: {
199	                            md: 'unset',
200	                            sm: semantics.light.neutral.background.primary
201	                          },
202	                          display: 'flex',
203	                          flexDirection: 'column',
204	                          gap: {md: '2rem', sm: '1rem'},
205	                          pt: {md: 0, sm: '1rem'},
206	                          px: {md: 0, sm: '1rem'},
207	                          pb: '1rem',
208	                          mb: '1rem',
209	                          borderBottom: {
210	                            sm: `1px solid ${semantics.light.neutral.border.default}`,
211	                            md: 'none'
212	                          }
213	                        }}>
214	                        {!pdpMobileBreakpoint && (
215	                          <ProductDetailsAndKeyBenefits />
216	                        )}
217	                        {!isPreview && <CustomerLooks />}
218	                        {!pdpMobileBreakpoint && (
219	                          <RelatedProducts
220	                            ref={similarRef}
221	                            forceTab={
222	                              RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE
223	                            }
224	                            showDivider={true}
225	                          />
226	                        )}
227	                        {!isPreview && <ProductReviews ref={reviewRef} />}
228	                        {pdpMobileBreakpoint && (
229	                          <RelatedProducts
230	                            ref={similarRef}
231	                            forceTab={
232	                              RELATED_PRODUCTS_TAB_KEY_YOU_MAY_ALSO_LIKE
233	                            }
234	                          />
235	                        )}
236	                        {productInfo && (
237	                          <MoreInfo name={name} productInfo={productInfo} />
238	                        )}
239	                      </Box>
240	                      {extraRecommendationsAnchor &&
241	                        ReactDOM.createPortal(
242	                          <ExtraRecommendations />,
243	                          extraRecommendationsAnchor
244	                        )}
245	                    </CurrentSelectedColorContext.Provider>
246	                  </ProductContext.Provider>
247	                </FavoritesProvider>
248	              </ProfilesAuthProvider>
249	            </PigmentThemeProvider>
250	          </QueryClientProvider>
251	        </MaybeSignalmizelyProvider>
252	      </ErrorBoundary>
253	    </RollbarProvider>
254	  );
255	};
256	
257	export default ProductDetailsPage;
258	
