1	import 'keen-slider/keen-slider.min.css';
2	import {semantics} from '@customink/design-tokens';
3	import {
4	  ArrowDownIcon,
5	  Box,
6	  Dialog,
7	  Skeleton,
8	  Typography
9	} from '@customink/pigment-react';
10	import {styled} from '@mui/material/styles';
11	import useResizeObserver from '@react-hook/resize-observer';
12	import {useKeenSlider} from 'keen-slider/react';
13	import React, {
14	  useCallback,
15	  useContext,
16	  useEffect,
17	  useMemo,
18	  useRef,
19	  useState
20	} from 'react';
21	import useBreakpoint from 'hooks/useBreakpoint';
22	import useCustomerLooks, {type Photo} from 'hooks/useCustomerLooks';
23	// @ts-expect-error - productContext is a JSX module without type declarations
24	import ProductContext from 'product_details_page/Context/productContext';
25	// @ts-expect-error - analytics is a JS module without type declarations
26	import {firePdpInteractionClickEvent} from 'utils/analytics';
27	import {
28	  CAROUSEL_GAP,
29	  DESKTOP_SLIDES_PER_VIEW,
30	  FETCH_THRESHOLD,
31	  MOBILE_SLIDES_PER_VIEW
32	} from './constants';
33	import CustomerLooksLightbox from './CustomerLooksLightbox';
34	import {ArrowButton, getPhotoAlt} from './CustomerLooksUtils';
35	
36	const containerSx = {
37	  margin: '0 auto',
38	  maxWidth: {lg: '63rem', xl: '80.25rem'},
39	  padding: {md: '0 1rem', sm: '0 0.5rem'},
40	  width: '100%'
41	};
42	
43	const headerRowSx = {
44	  alignItems: 'center',
45	  display: 'flex',
46	  justifyContent: 'space-between',
47	  marginBottom: '1rem'
48	};
49	
50	const photoSlideSx = {
51	  '& img': {
52	    borderRadius: semantics.units.radius.card,
53	    cursor: 'pointer',
54	    height: '100%',
55	    objectFit: 'cover',
56	    width: '100%'
57	  },
58	  aspectRatio: '1 / 1',
59	  height: '100%',
60	  width: '100%'
61	};
62	
63	const SliderWrapper = styled('div')(() => ({
64	  '.keen-slider': {
65	    display: 'flex',
66	    overflow: 'hidden',
67	    position: 'relative',
68	    touchAction: 'pan-y',
69	    userSelect: 'none',
70	    WebkitTouchCallout: 'none'
71	  },
72	  '.keen-slider__slide': {
73	    minHeight: '100%',
74	    overflow: 'hidden',
75	    position: 'relative'
76	  },
77	  overflow: 'hidden',
78	  position: 'relative',
79	  width: '100%'
80	}));
81	
82	const LoadingSkeleton: React.FC = () => (
83	  <Box sx={containerSx}>
84	    <Box sx={headerRowSx}>
85	      <Skeleton variant="text" width={120} height={28} />
86	      <Box sx={{display: 'flex', gap: 1}}>
87	        <Skeleton variant="circular" width={40} height={40} />
88	        <Skeleton variant="circular" width={40} height={40} />
89	      </Box>
90	    </Box>
91	    <Box sx={{display: 'flex', gap: semantics.units.space.componentLayout.sm}}>
92	      {[1, 2, 3, 4].map((i) => (
93	        <Skeleton
94	          key={i}
95	          variant="rectangular"
96	          sx={{
97	            aspectRatio: '1 / 1',
98	            borderRadius: semantics.units.radius.card,
99	            flex: 1
100	          }}
101	        />
102	      ))}
103	    </Box>
104	  </Box>
105	);
106	
107	const CustomerLooks: React.FC = () => {
108	  const {id: styleId} = useContext(ProductContext) as {id: string};
109	  const breakpoint = useBreakpoint() as string;
110	  const isMobile = breakpoint === 'sm';
111	  const {error, fetchNextPage, hasMore, isLoading, photos} =
112	    useCustomerLooks(styleId);
113	
114	  const [currentSlide, setCurrentSlide] = useState(0);
115	  const [sliderReady, setSliderReady] = useState(false);
116	  const [lightboxOpen, setLightboxOpen] = useState(false);
117	  const [lightboxIndex, setLightboxIndex] = useState(0);
118	
119	  const slidesPerView = useMemo(() => {
120	    if (isMobile) {
121	      return photos.length >= 2 ? MOBILE_SLIDES_PER_VIEW : photos.length;
122	    }
123	    return photos.length >= DESKTOP_SLIDES_PER_VIEW
124	      ? DESKTOP_SLIDES_PER_VIEW
125	      : photos.length;
126	  }, [isMobile, photos.length]);
127	  const gap = isMobile ? CAROUSEL_GAP.mobile : CAROUSEL_GAP.desktop;
128	
129	  const sliderMaxWidth = useMemo(() => {
130	    if (isMobile || photos.length >= DESKTOP_SLIDES_PER_VIEW) return '100%';
131	    return `${(photos.length / DESKTOP_SLIDES_PER_VIEW) * 100}%`;
132	  }, [isMobile, photos.length]);
133	
134	  const [sliderRef, instanceRef] = useKeenSlider(
135	    {
136	      created: () => {
137	        setSliderReady(true);
138	      },
139	      drag: true,
140	      initial: 0,
141	      loop: false,
142	      mode: 'free-snap',
143	      rubberband: true,
144	      slideChanged: (instance: {details: () => {relativeSlide: number}}) => {
145	        const slide = instance.details().relativeSlide;
146	        setCurrentSlide(slide);
147	        const lastVisibleIndex = slide + Math.floor(slidesPerView);
148	        if (hasMore && photos.length - lastVisibleIndex <= FETCH_THRESHOLD) {
149	          void fetchNextPage();
150	        }
151	      },
152	      slidesPerView,
153	      spacing: gap
154	    },
155	    // @ts-expect-error keen-slider types don't include the dependency array overload
156	    [slidesPerView, gap, hasMore, photos.length, fetchNextPage]
157	  );
158	
159	  const boundingBoxRef = useRef<HTMLDivElement>(null);
160	  useResizeObserver(boundingBoxRef, () => instanceRef?.refresh());
161	
162	  useEffect(() => {
163	    if (instanceRef && photos.length > 0) {
164	      instanceRef.refresh();
165	    }
166	  }, [instanceRef, photos.length]);
167	
168	  const handleLeftClick = useCallback(
169	    (e: React.MouseEvent) => {
170	      e.stopPropagation();
171	      if (currentSlide === 0) return;
172	      firePdpInteractionClickEvent('customer looks', 'previous arrow');
173	      instanceRef?.prev();
174	    },
175	    [instanceRef, currentSlide]
176	  );
177	
178	  const handleRightClick = useCallback(
179	    (e: React.MouseEvent) => {
180	      e.stopPropagation();
181	      if (currentSlide >= photos.length - Math.floor(slidesPerView)) return;
182	      firePdpInteractionClickEvent('customer looks', 'next arrow');
183	      instanceRef?.next();
184	    },
185	    [instanceRef, currentSlide, photos.length, slidesPerView]
186	  );
187	
188	  const handleImageClick = useCallback((index: number) => {
189	    firePdpInteractionClickEvent('customer looks', 'image');
190	    setLightboxIndex(index);
191	    setLightboxOpen(true);
192	  }, []);
193	
194	  const handleLightboxClose = useCallback(() => {
195	    setLightboxOpen(false);
196	  }, []);
197	
198	  if (isLoading) {
199	    return <LoadingSkeleton />;
200	  }
201	
202	  if (error || photos.length === 0) {
203	    return null;
204	  }
205	
206	  const showArrows = !isMobile && photos.length > slidesPerView;
207	  const isFirstSlide = currentSlide === 0;
208	  const isLastSlide = currentSlide >= photos.length - Math.floor(slidesPerView);
209	
210	  return (
211	    <>
212	      <Box
213	        sx={containerSx}
214	        data-testid="customer-looks"
215	        component="section"
216	        aria-label="Customer Looks">
217	        <Box sx={headerRowSx}>
218	          <Typography
219	            variant="uiTextDefault"
220	            fontSize="1.25rem"
221	            fontWeight="bold">
222	            Customer Looks
223	          </Typography>
224	          {showArrows && sliderReady && (
225	            <Box sx={{display: 'flex', gap: '0.5rem'}}>
226	              <ArrowButton
227	                disableRipple
228	                onClick={handleLeftClick}
229	                disabled={isFirstSlide}
230	                aria-label="Previous photos">
231	                <ArrowDownIcon
232	                  sx={{transform: 'rotate(90deg)'}}
233	                  fontSize="small"
234	                />
235	              </ArrowButton>
236	              <ArrowButton
237	                disableRipple
238	                onClick={handleRightClick}
239	                disabled={isLastSlide}
240	                aria-label="Next photos">
241	                <ArrowDownIcon
242	                  sx={{transform: 'rotate(-90deg)'}}
243	                  fontSize="small"
244	                />
245	              </ArrowButton>
246	            </Box>
247	          )}
248	        </Box>
249	        <SliderWrapper
250	          ref={boundingBoxRef}
251	          tabIndex={0}
252	          role="region"
253	          aria-label="Customer photos carousel"
254	          style={{maxWidth: sliderMaxWidth}}
255	          onKeyDown={(e: React.KeyboardEvent) => {
256	            if (e.key === 'ArrowLeft') {
257	              e.preventDefault();
258	              instanceRef?.prev();
259	            } else if (e.key === 'ArrowRight') {
260	              e.preventDefault();
261	              instanceRef?.next();
262	            }
263	          }}>
264	          <div
265	            ref={sliderRef as React.RefObject<HTMLDivElement>}
266	            className="keen-slider">
267	            {photos.map((photo: Photo, index: number) => (
268	              <Box
269	                key={photo.id ?? `customer-look-${index}`}
270	                className="keen-slider__slide"
271	                sx={photoSlideSx}
272	                onClick={() => handleImageClick(index)}
273	                onKeyDown={(e: React.KeyboardEvent) => {
274	                  if (e.key === 'Enter' || e.key === ' ') {
275	                    e.preventDefault();
276	                    handleImageClick(index);
277	                  }
278	                }}
279	                tabIndex={0}
280	                role="button"
281	                aria-label={`View ${getPhotoAlt(photo, index)}`}>
282	                <img
283	                  src={photo.photo_url}
284	                  alt={getPhotoAlt(photo, index)}
285	                  loading="lazy"
286	                />
287	              </Box>
288	            ))}
289	          </div>
290	        </SliderWrapper>
291	      </Box>
292	
293	      <Dialog
294	        open={lightboxOpen}
295	        onClose={handleLightboxClose}
296	        mobileVariant={isMobile ? 'fullScreen' : undefined}
297	        width="lg">
298	        {lightboxOpen && (
299	          <CustomerLooksLightbox
300	            styleId={styleId}
301	            initialIndex={lightboxIndex}
302	            onClose={handleLightboxClose}
303	            isMobile={isMobile}
304	          />
305	        )}
306	      </Dialog>
307	    </>
308	  );
309	};
310	
311	export default CustomerLooks;
312	
